    "openclaw": {"status": "online", "last_seen": time.time()},
    "hermes": {"status": "online", "last_seen": time.time()},
}

def notify_hermes():
    """Write a notification to Hermes's PTY if available."""
    try:
        if os.path.exists(PTY_PATH):
            with open(PTY_PATH, 'w') as f:
                f.write("\n[MSG] Nuovo messaggio in coda - usa /poll per leggerlo\n")
    except Exception:
        pass

def push_to_subscriber(agent, data):
    """Push message to SSE subscriber if connected."""
    q = subscribers.get(agent)
    if q is not None:
        try:
            q.put_nowait(data)
        except:
            pass

